import sys


def main():
    input_str = sys.stdin.readline().strip()
    shift = int(sys.stdin.readline().strip())
    print(shift_string(input_str, shift))


def shift_string(input_str, shift):
    shifted_str = ''
    for char in input_str:
        char_code = ord(char)
        if 97 <= char_code <= 122:
            char_code = (char_code - 97 + shift) % 26 + 97
        elif 65 <= char_code <= 90:
            char_code = (char_code - 65 + shift) % 26 + 65
        shifted_str += chr(char_code)
    return shifted_str


if __name__ == '__main__':
    main()
